import{_ as t,o as e,c as n,ae as s}from"./chunks/framework.L6C4hHZp.js";const u=JSON.parse('{"title":"Self-Evolution Mechanism","description":"","frontmatter":{},"headers":[],"relativePath":"self-evolution.md","filePath":"self-evolution.md"}'),o={name:"self-evolution.md"};function i(l,a,r,p,d,c){return e(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="self-evolution-mechanism" tabindex="-1">Self-Evolution Mechanism <a class="header-anchor" href="#self-evolution-mechanism" aria-label="Permalink to &quot;Self-Evolution Mechanism&quot;">​</a></h1><blockquote><p>This is what fundamentally distinguishes GenericAgent from every other agent framework.</p></blockquote><h2 id="_1-core-philosophy" tabindex="-1">1. Core Philosophy <a class="header-anchor" href="#_1-core-philosophy" aria-label="Permalink to &quot;1. Core Philosophy&quot;">​</a></h2><p><strong>Traditional Agent Frameworks</strong>: Pre-load hundreds of skills/tools, static capability set.</p><p><strong>GenericAgent</strong>: Don&#39;t preload skills — evolve them through use.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[遇到新任务] → [自主摸索] → [固化为Skill] → [下次直接调用]</span></span></code></pre></div><h2 id="_2-evolution-flow" tabindex="-1">2. Evolution Flow <a class="header-anchor" href="#_2-evolution-flow" aria-label="Permalink to &quot;2. Evolution Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                      New Task Arrives                        │</span></span>
<span class="line"><span>└──────────────────────────┬──────────────────────────────────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>                           ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              L1 Insight Index (Routing)                       │</span></span>
<span class="line"><span>│         &quot;Does a relevant L3 Skill exist?&quot;                    │</span></span>
<span class="line"><span>└──────────────────────────┬──────────────────────────────────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>              ┌────────────┴────────────┐</span></span>
<span class="line"><span>              ▼                         ▼</span></span>
<span class="line"><span>         [YES: Skill found]       [NO: No matching skill]</span></span>
<span class="line"><span>              │                         │</span></span>
<span class="line"><span>              ▼                         ▼</span></span>
<span class="line"><span>┌─────────────────────┐    ┌─────────────────────────────────┐</span></span>
<span class="line"><span>│ Direct Skill Recall │    │   Autonomous Exploration Mode   │</span></span>
<span class="line"><span>│ + Execute          │    │   1. Install dependencies       │</span></span>
<span class="line"><span>└─────────────────────┘    │   2. Write execution scripts   │</span></span>
<span class="line"><span>                           │   3. Debug and verify          │</span></span>
<span class="line"><span>                           │   4. Complete task             │</span></span>
<span class="line"><span>                           └──────────────┬──────────────────┘</span></span>
<span class="line"><span>                                          │</span></span>
<span class="line"><span>                                          ▼</span></span>
<span class="line"><span>                           ┌─────────────────────────────────┐</span></span>
<span class="line"><span>                           │   Skill Crystallization         │</span></span>
<span class="line"><span>                           │   (via start_long_term_update)  │</span></span>
<span class="line"><span>                           │                                 │</span></span>
<span class="line"><span>                           │   1. Analyze execution path     │</span></span>
<span class="line"><span>                           │   2. Generate SOP from path     │</span></span>
<span class="line"><span>                           │   3. Save to L3 Skills         │</span></span>
<span class="line"><span>                           │   4. Update L1 Insight Index   │</span></span>
<span class="line"><span>                           └──────────────┬──────────────────┘</span></span>
<span class="line"><span>                                          │</span></span>
<span class="line"><span>                                          ▼</span></span>
<span class="line"><span>                           ┌─────────────────────────────────┐</span></span>
<span class="line"><span>                           │   Next Similar Task            │</span></span>
<span class="line"><span>                           │   → Direct recall from L3      │</span></span>
<span class="line"><span>                           │   → &quot;一句话启动&quot;               │</span></span>
<span class="line"><span>                           └─────────────────────────────────┘</span></span></code></pre></div><h2 id="_3-self-evolution-example" tabindex="-1">3. Self-Evolution Example <a class="header-anchor" href="#_3-self-evolution-example" aria-label="Permalink to &quot;3. Self-Evolution Example&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Task</th><th>First Time</th><th>After Evolution</th></tr></thead><tbody><tr><td>&quot;Read my WeChat messages&quot;</td><td>Install deps → Reverse DB → Write script → Save skill</td><td><strong>one-line invoke</strong></td></tr><tr><td>&quot;Monitor stocks and alert me&quot;</td><td>Install mootdx → Build selection flow → Configure cron → Save skill</td><td><strong>one-line start</strong></td></tr><tr><td>&quot;Send this file via Gmail&quot;</td><td>Configure OAuth → Write send script → Save skill</td><td><strong>ready to use</strong></td></tr></tbody></table><h2 id="_4-skill-library" tabindex="-1">4. Skill Library <a class="header-anchor" href="#_4-skill-library" aria-label="Permalink to &quot;4. Skill Library&quot;">​</a></h2><p>After weeks of use, your GenericAgent instance will have a <strong>unique skill tree</strong> that no one else in the world has — all grown from 3K lines of seed code.</p><h3 id="skill-categories" tabindex="-1">Skill Categories <a class="header-anchor" href="#skill-categories" aria-label="Permalink to &quot;Skill Categories&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td>Platform Integration</td><td>Connect to external services</td><td>Gmail sending, WeChat reading</td></tr><tr><td>Data Processing</td><td>Transform and analyze data</td><td>Stock screening, expense tracking</td></tr><tr><td>Browser Automation</td><td>Web interaction patterns</td><td>Login, form filling, scraping</td></tr><tr><td>System Control</td><td>OS-level operations</td><td>ADB, keyboard/mouse, cron</td></tr></tbody></table><h2 id="_5-layered-memory-×-evolution" tabindex="-1">5. Layered Memory × Evolution <a class="header-anchor" href="#_5-layered-memory-×-evolution" aria-label="Permalink to &quot;5. Layered Memory × Evolution&quot;">​</a></h2><p>The self-evolution mechanism is tightly coupled with the layered memory system:</p><table tabindex="0"><thead><tr><th>Layer</th><th>Role in Evolution</th></tr></thead><tbody><tr><td>L0</td><td>Provides constraints (can&#39;t evolve past red lines)</td></tr><tr><td>L1</td><td>Routes to evolved skills (fast recall)</td></tr><tr><td>L2</td><td>Stores stable facts about what works</td></tr><tr><td>L3</td><td>Stores crystallized skills (main evolution output)</td></tr><tr><td>L4</td><td>Provides historical context for similar tasks</td></tr></tbody></table><h2 id="_6-code-as-documentation" tabindex="-1">6. Code-as-Documentation <a class="header-anchor" href="#_6-code-as-documentation" aria-label="Permalink to &quot;6. Code-as-Documentation&quot;">​</a></h2><p>GenericAgent agents can read their own code to understand and explain capabilities:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户: 告诉我你的reflect模式怎么启用</span></span>
<span class="line"><span>Agent: file_read(goal_mode_sop.md) → 提取约束 → 解释如何使用</span></span></code></pre></div><p>This means:</p><ul><li><strong>No external documentation required</strong> for basic usage</li><li>Agents self-document through code reading</li><li>New capabilities discovered through exploration</li></ul><h2 id="_7-self-bootstrap-proof" tabindex="-1">7. Self-Bootstrap Proof <a class="header-anchor" href="#_7-self-bootstrap-proof" aria-label="Permalink to &quot;7. Self-Bootstrap Proof&quot;">​</a></h2><blockquote><p>🤖 <strong>Self-Bootstrap Proof</strong> — Everything in the GenericAgent repository, from installing Git and running <code>git init</code> to every commit message, was completed autonomously by GenericAgent. The author never opened a terminal once.</p></blockquote><p>This demonstrates:</p><ol><li>Agent can set up its own environment</li><li>Agent can use Git for version control</li><li>Agent can commit with meaningful messages</li><li>Agent can troubleshoot and fix issues</li></ol><h2 id="_8-comparison-with-static-frameworks" tabindex="-1">8. Comparison with Static Frameworks <a class="header-anchor" href="#_8-comparison-with-static-frameworks" aria-label="Permalink to &quot;8. Comparison with Static Frameworks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>GenericAgent</th><th>Static Framework</th></tr></thead><tbody><tr><td>Initial capabilities</td><td>Minimal (3K code)</td><td>Rich (pre-loaded tools)</td></tr><tr><td>Capability growth</td><td>Auto-evolve via use</td><td>Manual plugin addition</td></tr><tr><td>Skill retention</td><td>Permanent (in L3)</td><td>Session-only or external</td></tr><tr><td>Customization</td><td>Agent learns your patterns</td><td>User configures plugins</td></tr><tr><td>Maintenance</td><td>Self-improving</td><td>Manual updates</td></tr></tbody></table><h2 id="_9-benefits" tabindex="-1">9. Benefits <a class="header-anchor" href="#_9-benefits" aria-label="Permalink to &quot;9. Benefits&quot;">​</a></h2><table tabindex="0"><thead><tr><th>For Users</th><th>For Developers</th></tr></thead><tbody><tr><td>Lower barrier to entry</td><td>Minimal seed code to maintain</td></tr><tr><td>Personalized skill tree</td><td>Capabilities grow automatically</td></tr><tr><td>No plugin management</td><td>Agent handles dependencies</td></tr><tr><td>&quot;Set and forget&quot;</td><td>Self-debugging and recovery</td></tr></tbody></table><h2 id="_10-technical-report" tabindex="-1">10. Technical Report <a class="header-anchor" href="#_10-technical-report" aria-label="Permalink to &quot;10. Technical Report&quot;">​</a></h2><p>For academic details on the self-evolution mechanism, see:</p><ul><li><a href="https://arxiv.org/abs/2604.17091" target="_blank" rel="noreferrer">arXiv:2604.17091</a> — <em>GenericAgent: A Token-Efficient Self-Evolving LLM Agent via Contextual Information Density Maximization</em></li></ul>`,33)])])}const m=t(o,[["render",i]]);export{u as __pageData,m as default};
